import{c as a,Q as s,j as t,m as i}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"How Claude Code Works — Agentic Loop、Tools、Context 管理","description":"","frontmatter":{"title":"How Claude Code Works — Agentic Loop、Tools、Context 管理","source":"https://code.claude.com/docs/en/how-claude-code-works","type":"best-practices"},"headers":[],"relativePath":"research/best-practices/18-how-claude-code-works.md","filePath":"research/best-practices/18-how-claude-code-works.md","lastUpdated":1779935873000}'),o={name:"research/best-practices/18-how-claude-code-works.md"};function n(d,e,l,r,c,h){return s(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="how-claude-code-works-—-agentic-loop、tools、context-管理" tabindex="-1">How Claude Code Works — Agentic Loop、Tools、Context 管理 <a class="header-anchor" href="#how-claude-code-works-—-agentic-loop、tools、context-管理" aria-label="Permalink to &quot;How Claude Code Works — Agentic Loop、Tools、Context 管理&quot;">​</a></h1><blockquote><p>來源：<a href="https://code.claude.com/docs/en/how-claude-code-works" target="_blank" rel="noreferrer">https://code.claude.com/docs/en/how-claude-code-works</a> 收錄日期：2026-05-01 涵蓋：Agentic Loop 三階段、五類 Built-in Tools、Session 管理、Checkpoint、Permission Modes</p></blockquote><hr><h2 id="agentic-loop" tabindex="-1">Agentic Loop <a class="header-anchor" href="#agentic-loop" aria-label="Permalink to &quot;Agentic Loop&quot;">​</a></h2><p>Claude Code 透過三個階段解決問題，且各階段會彼此交織：</p><table tabindex="0"><thead><tr><th>階段</th><th>說明</th></tr></thead><tbody><tr><td><strong>Gather context</strong></td><td>搜尋檔案、讀取程式碼、理解環境</td></tr><tr><td><strong>Take action</strong></td><td>編輯檔案、執行指令、查詢 web</td></tr><tr><td><strong>Verify results</strong></td><td>跑測試、對比截圖、確認輸出</td></tr></tbody></table><p>Loop 依任務自動調整：一個問題可能只需要 context gathering；一個 bug fix 則反覆循環三個階段數十次。你可以隨時中斷 Claude 重新引導。</p><p><strong>核心架構</strong>：Claude Code 是 Claude 的 <strong>agentic harness</strong>，提供 tools、context 管理、執行環境，讓語言模型成為能力完整的 coding agent。</p><hr><h2 id="models" tabindex="-1">Models <a class="header-anchor" href="#models" aria-label="Permalink to &quot;Models&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模型</th><th>適用</th></tr></thead><tbody><tr><td>Sonnet</td><td>多數 coding 任務</td></tr><tr><td>Opus</td><td>複雜架構決策，需要更強推理</td></tr></tbody></table><p>Session 內切換：<code>/model</code>；啟動時指定：<code>claude --model &lt;name&gt;</code></p><hr><h2 id="built-in-tools-五類" tabindex="-1">Built-in Tools（五類） <a class="header-anchor" href="#built-in-tools-五類" aria-label="Permalink to &quot;Built-in Tools（五類）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>類別</th><th>Claude 能做什麼</th></tr></thead><tbody><tr><td><strong>File operations</strong></td><td>讀取、編輯、建立、重新命名與重組</td></tr><tr><td><strong>Search</strong></td><td>按 pattern 找檔案、regex 搜尋內容、探索 codebase</td></tr><tr><td><strong>Execution</strong></td><td>執行 shell 指令、啟動 server、跑測試、使用 git</td></tr><tr><td><strong>Web</strong></td><td>搜尋 web、抓取文件、查詢錯誤訊息</td></tr><tr><td><strong>Code intelligence</strong></td><td>看編輯後的 type errors 和 warnings、跳定義、找 references（需安裝 code intelligence plugins）</td></tr></tbody></table><p>Claude 還有 spawn subagents、向你提問等 orchestration 工具。完整清單：<code>/en/tools-reference</code></p><p><strong>擴展基礎能力</strong>：Skills 擴展知識、MCP 連接外部服務、Hooks 自動化工作流、Subagents 卸載任務。</p><h3 id="native-binaries-w16-w17-v2-1-113" tabindex="-1">Native Binaries（W16+W17, v2.1.113） <a class="header-anchor" href="#native-binaries-w16-w17-v2-1-113" aria-label="Permalink to &quot;Native Binaries（W16+W17, v2.1.113）&quot;">​</a></h3><p><code>claude</code> CLI 改為 per-platform native binary，透過 npm optional dependency 安裝（如 <code>@anthropic-ai/claude-code-darwin-arm64</code>）。升級方式不變：<code>claude update</code>。</p><p>W17 補充：macOS / Linux builds 中 Glob / Grep tool 替換為 embedded <code>bfs</code> / <code>ugrep</code>，搜尋速度更快，不需獨立 tool round-trip。</p><h3 id="powershell-tool-w13-v2-1-84-preview" tabindex="-1">PowerShell Tool（W13, v2.1.84，preview） <a class="header-anchor" href="#powershell-tool-w13-v2-1-84-preview" aria-label="Permalink to &quot;PowerShell Tool（W13, v2.1.84，preview）&quot;">​</a></h3><p>Windows 專屬，Claude 可執行 cmdlet、pipe 物件、使用 Windows 路徑。啟用：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;env&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;CLAUDE_CODE_USE_POWERSHELL_TOOL&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="windows-無需-git-bash-w18-v2-1-120" tabindex="-1">Windows 無需 Git Bash（W18, v2.1.120） <a class="header-anchor" href="#windows-無需-git-bash-w18-v2-1-120" aria-label="Permalink to &quot;Windows 無需 Git Bash（W18, v2.1.120）&quot;">​</a></h3><p>Git for Windows 不再必要。當 Bash 不存在時，Claude Code 自動改用 PowerShell 作為 shell 工具。PowerShell 7 無論透過 Microsoft Store、MSI 或 <code>.NET</code> global tool 安裝，均能自動偵測。</p><h3 id="claude-code-perforce-mode-w15" tabindex="-1"><code>CLAUDE_CODE_PERFORCE_MODE</code>（W15） <a class="header-anchor" href="#claude-code-perforce-mode-w15" aria-label="Permalink to &quot;\`CLAUDE_CODE_PERFORCE_MODE\`（W15）&quot;">​</a></h3><p>Edit / Write 在唯讀檔案失敗時提示執行 <code>p4 edit</code> 而非靜默覆蓋，適合 Perforce 托管的 codebase：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CLAUDE_CODE_PERFORCE_MODE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span></code></pre></div><hr><h2 id="claude-code-存取範圍" tabindex="-1">Claude Code 存取範圍 <a class="header-anchor" href="#claude-code-存取範圍" aria-label="Permalink to &quot;Claude Code 存取範圍&quot;">​</a></h2><p>在目錄中執行 <code>claude</code> 後，Claude Code 可存取：</p><ul><li><strong>你的專案</strong> — 目錄內及子目錄的檔案（其他路徑需授權）</li><li><strong>你的 terminal</strong> — 任何你能執行的指令（build tools、git、package managers、scripts）</li><li><strong>你的 git state</strong> — 當前 branch、未 commit 的變更、近期 commit history</li><li><strong>CLAUDE.md</strong> — 每次 session 都讀入的專案指令</li><li><strong>Auto memory</strong> — Claude 自動累積的學習（MEMORY.md 前 200 行或 25KB）</li><li><strong>已設定的 extensions</strong> — MCP servers、Skills、Subagents、Claude in Chrome</li></ul><p>因為 Claude 看到整個專案，它能跨檔案工作：搜尋相關檔案、讀取多個檔案理解 context、協調修改多個檔案、跑測試驗證修正、依需求 commit。</p><hr><h2 id="執行環境" tabindex="-1">執行環境 <a class="header-anchor" href="#執行環境" aria-label="Permalink to &quot;執行環境&quot;">​</a></h2><table tabindex="0"><thead><tr><th>環境</th><th>程式碼在哪執行</th><th>用途</th></tr></thead><tbody><tr><td><strong>Local</strong></td><td>你的機器</td><td>預設；完整存取檔案、工具、環境</td></tr><tr><td><strong>Cloud</strong></td><td>Anthropic 管理的 VM</td><td>卸載任務、操作你沒有 locally 的 repo</td></tr><tr><td><strong>Remote Control</strong></td><td>你的機器，由瀏覽器控制</td><td>使用 web UI 同時保持一切在 local</td></tr></tbody></table><p><strong>Interface 選項</strong>：terminal、desktop app、IDE extensions（VS Code、JetBrains）、claude.ai/code、Remote Control、Slack、CI/CD pipelines。</p><h3 id="os-ca-certificate-trust-w15" tabindex="-1">OS CA Certificate Trust（W15） <a class="header-anchor" href="#os-ca-certificate-trust-w15" aria-label="Permalink to &quot;OS CA Certificate Trust（W15）&quot;">​</a></h3><p>預設信任系統 CA store，enterprise TLS proxy 不需額外設定憑證。</p><h3 id="push-notification-w16" tabindex="-1">Push Notification（W16） <a class="header-anchor" href="#push-notification-w16" aria-label="Permalink to &quot;Push Notification（W16）&quot;">​</a></h3><p>Remote Control 連接後，在 Remote Control 設定開啟「Push when Claude decides」→ Claude 可推播手機通知（適合長任務背景執行時通知完成）。</p><h3 id="claude-auth-login-無瀏覽器回調-w18-v2-1-126" tabindex="-1"><code>claude auth login</code> 無瀏覽器回調（W18, v2.1.126） <a class="header-anchor" href="#claude-auth-login-無瀏覽器回調-w18-v2-1-126" aria-label="Permalink to &quot;\`claude auth login\` 無瀏覽器回調（W18, v2.1.126）&quot;">​</a></h3><p>WSL2、SSH session、container 等無法 localhost 回調的環境，可直接在 terminal 貼入 OAuth code 完成登入：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 瀏覽器開啟後，將頁面上的 code 貼入 terminal</span></span></code></pre></div><hr><h2 id="tui-終端體驗" tabindex="-1">TUI / 終端體驗 <a class="header-anchor" href="#tui-終端體驗" aria-label="Permalink to &quot;TUI / 終端體驗&quot;">​</a></h2><h3 id="flicker-free-rendering-w14-v2-1-89" tabindex="-1">Flicker-free Rendering（W14, v2.1.89） <a class="header-anchor" href="#flicker-free-rendering-w14-v2-1-89" aria-label="Permalink to &quot;Flicker-free Rendering（W14, v2.1.89）&quot;">​</a></h3><p>Alt-screen renderer + virtualized scrollback。prompt input 釘在底部，支援跨長對話的滑鼠選取，消除重繪 flicker。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CLAUDE_CODE_NO_FLICKER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span></span></code></pre></div><h3 id="tui-command-w16" tabindex="-1"><code>/tui</code> command（W16） <a class="header-anchor" href="#tui-command-w16" aria-label="Permalink to &quot;\`/tui\` command（W16）&quot;">​</a></h3><p>Session 中切換 classic / flicker-free renderer，不需重啟：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /tui</span></span></code></pre></div><h3 id="custom-themes-w17-v2-1-118" tabindex="-1">Custom Themes（W17, v2.1.118） <a class="header-anchor" href="#custom-themes-w17-v2-1-118" aria-label="Permalink to &quot;Custom Themes（W17, v2.1.118）&quot;">​</a></h3><p><code>/theme</code> 開啟 picker，選擇命名 color scheme；也可手動編輯 <code>~/.claude/themes/</code> 中的 JSON（每個 theme 選 base preset 並覆蓋特定 token）。Plugin 也可打包 theme。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /theme    # 開啟 theme picker</span></span></code></pre></div><h3 id="vim-visual-mode-w17" tabindex="-1">Vim Visual Mode（W17） <a class="header-anchor" href="#vim-visual-mode-w17" aria-label="Permalink to &quot;Vim Visual Mode（W17）&quot;">​</a></h3><p>在 prompt input 按 <code>v</code>（字元選取）或 <code>V</code>（行選取），支援 operator：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>v    # 字元選取模式</span></span>
<span class="line"><span>V    # 行選取模式</span></span></code></pre></div><h3 id="claude-code-disable-alternate-screen-1-w19" tabindex="-1"><code>CLAUDE_CODE_DISABLE_ALTERNATE_SCREEN=1</code>（W19） <a class="header-anchor" href="#claude-code-disable-alternate-screen-1-w19" aria-label="Permalink to &quot;\`CLAUDE_CODE_DISABLE_ALTERNATE_SCREEN=1\`（W19）&quot;">​</a></h3><p>關閉全螢幕 alternate-screen 渲染，回到 terminal 原生 scrollback（與 <code>CLAUDE_CODE_NO_FLICKER=1</code> 效果不同，此環境變數完全關閉 alternate screen）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CLAUDE_CODE_DISABLE_ALTERNATE_SCREEN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span></code></pre></div><hr><h2 id="session-管理" tabindex="-1">Session 管理 <a class="header-anchor" href="#session-管理" aria-label="Permalink to &quot;Session 管理&quot;">​</a></h2><p>對話 session 儲存在 <code>~/.claude/projects/</code> 的 JSONL 檔案中，支援 rewind、resume、fork。</p><p><strong>Sessions 是獨立的</strong>：每個新 session 從乾淨的 context window 開始，不帶前次對話歷史。跨 session 的知識持久化靠 auto memory 和 CLAUDE.md。</p><h3 id="跨-branch-工作" tabindex="-1">跨 Branch 工作 <a class="header-anchor" href="#跨-branch-工作" aria-label="Permalink to &quot;跨 Branch 工作&quot;">​</a></h3><p>Session 綁定到當前目錄。切換 branch 後 Claude 看到新 branch 的檔案，但對話歷史保持不變（Claude 還記得你說了什麼）。</p><p>平行 session：用 git worktrees 建立獨立目錄，各跑一個 Claude session。</p><h3 id="transcript-search-w13-v2-1-83" tabindex="-1">Transcript Search（W13, v2.1.83） <a class="header-anchor" href="#transcript-search-w13-v2-1-83" aria-label="Permalink to &quot;Transcript Search（W13, v2.1.83）&quot;">​</a></h3><p>在 transcript mode 按 <code>/</code> 搜尋，<code>n</code> / <code>N</code> 前後跳轉：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Ctrl+O    # 開啟 transcript</span></span>
<span class="line"><span>/migrate  # 搜尋關鍵字</span></span>
<span class="line"><span>n         # 下一個結果</span></span>
<span class="line"><span>N         # 上一個結果</span></span></code></pre></div><h3 id="session-recap-w17-正式功能" tabindex="-1">Session Recap（W17 正式功能） <a class="header-anchor" href="#session-recap-w17-正式功能" aria-label="Permalink to &quot;Session Recap（W17 正式功能）&quot;">​</a></h3><p>切換 focus 後回來看到一行摘要，適合同時跑多個 Claude session：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /recap    # 手動觸發</span></span>
<span class="line"><span># 顯示：* recap: Fixing the post-submit transcript shift bug. PR #29869. Next: ...</span></span></code></pre></div><p>在 <code>/config</code> 關閉自動 recap。</p><h3 id="claude-code-session-id-w19" tabindex="-1"><code>CLAUDE_CODE_SESSION_ID</code>（W19） <a class="header-anchor" href="#claude-code-session-id-w19" aria-label="Permalink to &quot;\`CLAUDE_CODE_SESSION_ID\`（W19）&quot;">​</a></h3><p>此環境變數現在傳遞到 Bash tool 子程序環境，與 hooks 接收的 <code>session_id</code> 一致。Hook scripts 可透過 <code>$CLAUDE_CODE_SESSION_ID</code> 取得當前 session ID，方便跨工具關聯追蹤：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Current session: </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$CLAUDE_CODE_SESSION_ID</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div><h3 id="resume-或-fork-sessions" tabindex="-1">Resume 或 Fork Sessions <a class="header-anchor" href="#resume-或-fork-sessions" aria-label="Permalink to &quot;Resume 或 Fork Sessions&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --continue</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 繼續最近的 session（同一 session ID）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --resume</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 選擇最近的 sessions</span></span></code></pre></div><p>Fork（不影響原 session）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --continue</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --fork-session</span></span></code></pre></div><p><strong>同一 session 在多個 terminal</strong>：訊息會交錯（像兩人寫同一本筆記本）。平行工作請用 <code>--fork-session</code>。</p><hr><h2 id="context-window-管理" tabindex="-1">Context Window 管理 <a class="header-anchor" href="#context-window-管理" aria-label="Permalink to &quot;Context Window 管理&quot;">​</a></h2><p>Context 包含：對話歷史、檔案內容、指令輸出、CLAUDE.md、auto memory、loaded skills、system instructions。</p><p><strong>Context 填滿時</strong>：Claude Code 先清除較舊的工具輸出，若有需要再摘要整個對話。重要的 code snippets 會保留；早期詳細指令可能遺失 → <strong>把持久規則放進 CLAUDE.md</strong>。</p><p>MCP tool definitions 預設延遲載入，透過 tool search 按需取得 schema，只有 tool 名稱佔用 context。</p><p><strong>管理 context 的工具</strong>：</p><ul><li>Skills 按需載入（只有描述在 session 開始時載入）</li><li>Subagents 有自己獨立的 context，不污染主對話</li></ul><hr><h2 id="安全機制" tabindex="-1">安全機制 <a class="header-anchor" href="#安全機制" aria-label="Permalink to &quot;安全機制&quot;">​</a></h2><h3 id="checkpoints-undo-檔案變更" tabindex="-1">Checkpoints（Undo 檔案變更） <a class="header-anchor" href="#checkpoints-undo-檔案變更" aria-label="Permalink to &quot;Checkpoints（Undo 檔案變更）&quot;">​</a></h3><p>Claude 編輯任何檔案前先建立快照。出問題時：按 <code>Esc</code> 兩次 rewind 到前一狀態，或請 Claude undo。</p><p>Checkpoints 是 session local，獨立於 git。<strong>只覆蓋檔案變更；影響遠端系統（資料庫、API、部署）的操作無法 checkpoint。</strong></p><h3 id="permission-modes-shift-tab-循環切換" tabindex="-1">Permission Modes（<code>Shift+Tab</code> 循環切換） <a class="header-anchor" href="#permission-modes-shift-tab-循環切換" aria-label="Permalink to &quot;Permission Modes（\`Shift+Tab\` 循環切換）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>說明</th></tr></thead><tbody><tr><td><strong>Default</strong></td><td>所有檔案編輯和 shell 指令都需確認</td></tr><tr><td><strong>Auto-accept edits</strong></td><td>自動接受檔案編輯和常見 filesystem 指令（<code>mkdir</code>、<code>mv</code>），其他指令仍詢問</td></tr><tr><td><strong>Plan mode</strong></td><td>只用 read-only 工具，建立計畫讓你審核後再執行</td></tr><tr><td><strong>Auto mode</strong></td><td>後台安全檢查評估所有操作（research preview）</td></tr></tbody></table><p><code>.claude/settings.json</code> 可允許特定指令（如 <code>npm test</code>、<code>git status</code>）讓 Claude 不必每次詢問。</p><hr><h2 id="有效使用技巧" tabindex="-1">有效使用技巧 <a class="header-anchor" href="#有效使用技巧" aria-label="Permalink to &quot;有效使用技巧&quot;">​</a></h2><h3 id="像對話一樣操作" tabindex="-1">像對話一樣操作 <a class="header-anchor" href="#像對話一樣操作" aria-label="Permalink to &quot;像對話一樣操作&quot;">​</a></h3><p>不需要完美的 prompt。先說需要什麼，然後精煉：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Fix the login bug</span></span></code></pre></div><p>[Claude 調查、嘗試]</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>That&#39;s not quite right. The issue is in the session handling.</span></span></code></pre></div><p>[Claude 調整方法]</p><p>可以隨時中斷（不需等 Claude 完成）。</p><h3 id="讓-claude-從特定位置找答案" tabindex="-1">讓 Claude 從特定位置找答案 <a class="header-anchor" href="#讓-claude-從特定位置找答案" aria-label="Permalink to &quot;讓 Claude 從特定位置找答案&quot;">​</a></h3><p>直接說：<code>Use &#39;foo-cli-tool --help&#39; to learn about foo tool, then use it to solve A, B, C.</code></p><h3 id="先探索再實作" tabindex="-1">先探索再實作 <a class="header-anchor" href="#先探索再實作" aria-label="Permalink to &quot;先探索再實作&quot;">​</a></h3><p>複雜問題用 Plan Mode（<code>Shift+Tab</code> 兩次）先分析 codebase：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Read src/auth/ and understand how we handle sessions.</span></span>
<span class="line"><span>Then create a plan for adding OAuth support.</span></span></code></pre></div><h3 id="委派而非指揮" tabindex="-1">委派而非指揮 <a class="header-anchor" href="#委派而非指揮" aria-label="Permalink to &quot;委派而非指揮&quot;">​</a></h3><p>給 context 和方向，讓 Claude 決定細節：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>The checkout flow is broken for users with expired cards.</span></span>
<span class="line"><span>The relevant code is in src/payments/. Can you investigate and fix it?</span></span></code></pre></div><hr><h2 id="related-resources" tabindex="-1">Related Resources <a class="header-anchor" href="#related-resources" aria-label="Permalink to &quot;Related Resources&quot;">​</a></h2><ul><li><a href="/cc-workspace-docs/en/common-workflows">Common workflows</a> — 逐步指南（debug、測試、PR 等）</li><li><a href="/cc-workspace-docs/en/features-overview">Extend Claude Code</a> — Skills、MCP、自訂指令</li></ul>`,118)])])}const g=a(o,[["render",n]]);export{u as __pageData,g as default};
